const today = new Date();
const results = [];

for (const item of $input.all()) {
  const lead = item.json;

  const lastContact = new Date(lead.last_contact_date);
  const diffDays = Math.floor((today - lastContact) / (1000 * 60 * 60 * 24));

  let urgencyLevel = null;

  if (diffDays >= 14) {
    urgencyLevel = 'CRITICAL';
  } else if (diffDays >= 7) {
    urgencyLevel = 'HIGH';
  } else if (diffDays >= 3) {
    urgencyLevel = 'MEDIUM';
  }

  if (urgencyLevel) {
    results.push({
      json: {
        ...lead,
        days_inactive: diffDays,
        urgency_level: urgencyLevel
      }
    });
  }
}

return results;

// Loop over input items and add a new field called 'myNewField' to the JSON of each one
const lead = $input.first().json;

let emailBody = '';

if (lead.urgency_level === 'MEDIUM') {
  emailBody = `Hi ${lead.salesperson_name},

This is a reminder that you have not followed up with ${lead.lead_name} from ${lead.company}, ${lead.city} in ${lead.days_inactive} days.

Lead Status: ${lead.status}
Deal Value: INR ${lead.deal_value}
Last Contact: ${lead.last_contact_date}

Please take action at the earliest to avoid losing this deal.

Regards,
Sales Automation System`;

} else if (lead.urgency_level === 'HIGH') {
  emailBody = `Hi ${lead.salesperson_name},

URGENT: ${lead.lead_name} from ${lead.company} has not been contacted in ${lead.days_inactive} days. Your manager has been CC'd on this email.

Lead Status: ${lead.status}
Deal Value: INR ${lead.deal_value}
Last Contact: ${lead.last_contact_date}

Immediate action is required. Please update the CRM after your follow-up.

Regards,
Sales Automation System`;

} else if (lead.urgency_level === 'CRITICAL') {
  emailBody = `Dear ${lead.manager_name},

This is an automated alert. The lead ${lead.lead_name} from ${lead.company} has not been contacted in ${lead.days_inactive} days and has been automatically marked as DEAD in the system.

Deal Value Lost: INR ${lead.deal_value}
Assigned To: ${lead.salesperson_name}
Last Contact: ${lead.last_contact_date}

Please review the pipeline and take necessary action.

Regards,
Sales Automation System`;
}

return [{
  json: {
    ...lead,
    email_body: emailBody
  }
}];

